Rules.InvariantScript:
If(
    // JOB ENTRY
    gblProjectSidebarItemCurrent.Category = "Job Entry",
    With(
        {
            varType: "colCdsJobEntries",
            varRecordRef: gblRecordJobEntryCurrent_.'Job Entry'
        },
        // Check if the record was added by the app
        If(
            varRecordRef in Filter(
                colAUDRecords,
                Type = "colCdsJobEntries",
                Operation = "A"
            ).RecordRef,
            // for records added by the app
            //
            ////PHOTOS
            // remove job photos from new records
            RemoveIf(
                colAUDRecords,
                Type = "colCdsJobPhotos" And RecordRef in Filter(
                    colCdsJobPhotos,
                    'Job Entry'.'Job Entry' = varRecordRef
                ).'Job Photo' And Operation = "A"
            );
            // Delete job photos from local collection
            RemoveIf(
                colCdsJobPhotos,
                'Job Entry'.'Job Entry' = varRecordRef
            );
            //// WINDOW MEASUREMENTS
            // remove job entry selections from new records
            RemoveIf(
                colAUDRecords,
                Type = "colCdsWindowMeasurements" And RecordRef in Filter(
                    colCdsWindowMeasurements,
                    'Job Entry'.'Job Entry' = varRecordRef
                ).'Window Measurement' And Operation = "A"
            );
            // Delete window measurements from local collection
            RemoveIf(
                colCdsWindowMeasurements,
                'Job Entry'.'Job Entry' = varRecordRef
            );
            //// JOB ENTRY SELECTIONS
            // remove job entry selections from new records
            RemoveIf(
                colAUDRecords,
                Type = "colCdsJobEntrySelections" And RecordRef in Filter(
                    colCdsJobEntrySelections,
                    'Job Entry'.'Job Entry' = varRecordRef
                ).'Job Entry Selection' And Operation = "A"
            );
            //// JOB ENTRIES
            // remove job entries from new records
            Remove(
                colAUDRecords,
                LookUp(
                    colAUDRecords,
                    Type = "colCdsJobEntries" And RecordRef = varRecordRef And Operation = "A"
                )
            ),
            // for records found in CDS
            //
            // Add job photos to be deleted
            With(
                {
                    varJobPhotos: Filter(
                        colCdsJobPhotos,
                        'Job Entry'.'Job Entry' = gblRecordJobEntryCurrent_.'Job Entry'
                    )
                },
                Collect(
                    colAUDRecords,
                    ForAll(
                        varJobPhotos,
                        {
                            Type: "colCdsJobPhotos",
                            RecordRef: varJobPhotos[@'Job Photo'],
                            Job: gblRecordJobCurrent.Job,
                            Operation: "D"
                        }
                    )
                );
                UpdateIf(
                    colCdsJobPhotos,
                    'Job Photo' in varJobPhotos.'Job Photo',
                    {
                        Status: gblOptionSets.JobPhoto.Status.Inactive,
                        'Status Reason': gblOptionSets.JobPhoto.StatusReason.Inactive
                    }
                )
            );
            // Add window measurements to be deleted
            With(
                {
                    varWindowMeasurements: Filter(
                        colCdsWindowMeasurements,
                        'Job Entry'.'Job Entry' = gblRecordJobEntryCurrent_.'Job Entry'
                    )
                },
                Collect(
                    colAUDRecords,
                    ForAll(
                        varWindowMeasurements,
                        {
                            Type: "colCdsWindowMeasurements",
                            RecordRef: varWindowMeasurements[@'Window Measurement'],
                            Job: gblRecordJobCurrent.Job,
                            Operation: "D"
                        }
                    )
                );
                UpdateIf(
                    colCdsWindowMeasurements,
                    'Window Measurement' in varWindowMeasurements.'Window Measurement',
                    {
                        Status: gblOptionSets.WindowMeasurement.Status.Inactive,
                        'Status Reason': gblOptionSets.WindowMeasurement.StatusReason.Inactive
                    }
                )
            );
            // Add job entry selections to be deleted
            With(
                {
                    varJobEntrySelections: Filter(
                        colCdsJobEntrySelections,
                        'Job Entry'.'Job Entry' = gblRecordJobEntryCurrent_.'Job Entry'
                    )
                },
                Collect(
                    colAUDRecords,
                    ForAll(
                        varJobEntrySelections,
                        {
                            Type: "colCdsJobEntrySelections",
                            RecordRef: varJobEntrySelections[@'Job Entry Selection'],
                            Job: gblRecordJobCurrent.Job,
                            Operation: "D"
                        }
                    )
                );
                UpdateIf(
                    colCdsJobEntrySelections,
                    'Job Entry Selection' in varJobEntrySelections.'Job Entry Selection',
                    {
                        Status: gblOptionSets.JobEntrySelection.Status.Inactive,
                        'Status Reason': gblOptionSets.JobEntrySelection.StatusReason.Inactive
                    }
                )
            );
            // Add job entry to be deleted
            With(
                {varRecordRef: gblRecordJobEntryCurrent_.'Job Entry'},
                Collect(
                    colAUDRecords,
                    {
                        Type: "colCdsJobEntries",
                        RecordRef: varRecordRef,
                        Job: gblRecordJobCurrent.Job,
                        Operation: "D"
                    }
                );
                UpdateIf(
                    colCdsJobEntries,
                    'Job Entry' = varRecordRef,
                    {
                        Status: gblOptionSets.JobEntry.Status.Inactive,
                        'Status Reason': gblOptionSets.JobEntry.StatusReason.Inactive
                    }
                )
            )
        )
    );
    // save local changes
    If(
        gblAppLoadOffline,
        SaveData(
            colAUDRecords,
            "localAUDRecords"
        );
        SaveData(
            colCdsJobEntries,
            "localCdsJobEntries"
        );
        SaveData(
            colCdsJobEntrySelections,
            "localCdsJobEntrySelections"
        );
        SaveData(
            colCdsWindowMeasurements,
            "localCdsWindowMeasurements"
        );
        SaveData(
            colCdsJobPhotos,
            "localCdsJobPhotos"
        )
    );
    // go to the next screen
    Navigate(
        'Rooms Screen',
        BorderStyle.None
    ),
    // WINDOW MEASUREMENT
    gblProjectSidebarItemCurrent.Category = "Window Measurement",
    With(
        {
            varType: "colCdsWindowMeasurements",
            varRecordRef: gblRecordWindowMeasurement_Tech.'Window Measurement'
        },
        // Check if the record was added by the app
        If(
            varRecordRef in Filter(
                colAUDRecords,
                Type = "colCdsWindowMeasurements",
                Operation = "A"
            ).RecordRef,
            // remove job entry selections from new records
            RemoveIf(
                colAUDRecords,
                And(
                    Type = "colCdsWindowMeasurements",
                    RecordRef = gblRecordWindowMeasurement_Tech.'Window Measurement',
                    Operation = "A"
                )
            );
            RemoveIf(
                colCdsWindowMeasurements,
                'Window Measurement' = varRecordRef
            ); 
            //// PHOTOS
            // remove job photos from new records
            RemoveIf(
                colAUDRecords,
                Type = "colCdsJobPhotos" And RecordRef in Filter(
                    colCdsJobPhotos,
                    'Window Measurement'.'Window Measurement' = varRecordRef
                ).'Job Photo' And Operation = "A"
            );
            // Delete job photos from local collection
            RemoveIf(
                colCdsJobPhotos,
                'Window Measurement'.'Window Measurement' = varRecordRef
            );
            // remove current job entry from not completed windows collection
            Remove(
                colNotCompletedWindows,
                LookUp(colNotCompletedWindows, 'Window Measurement'=gblRecordWindowMeasurement_Tech.'Window Measurement') 
            ),
            // Add window measurements to be deleted
            Collect(
                colAUDRecords,
                {
                    Type: "colCdsWindowMeasurements",
                    RecordRef: gblRecordWindowMeasurement_Tech.'Window Measurement',
                    Job: gblRecordJobCurrent.Job,
                    Operation: "D"
                }
            );
            UpdateIf(
                colCdsWindowMeasurements,
                'Window Measurement' = gblRecordWindowMeasurement_Tech.'Window Measurement',
                {
                    Status: gblOptionSets.WindowMeasurement.Status.Inactive,
                    'Status Reason': gblOptionSets.WindowMeasurement.StatusReason.Inactive
                }
            );
            // Add job photos to be deleted
            With(
                {
                    varJobPhotos: Filter(
                        colCdsJobPhotos,
                        'Window Measurement'.'Window Measurement' = varRecordRef
                    )
                },
                Collect(
                    colAUDRecords,
                    ForAll(
                        varJobPhotos,
                        {
                            Type: "colCdsJobPhotos",
                            RecordRef: varJobPhotos[@'Job Photo'],
                            Job: gblRecordJobCurrent.Job,
                            Operation: "D"
                        }
                    )
                );
                UpdateIf(
                    colCdsJobPhotos,
                    'Job Photo' in varJobPhotos.'Job Photo',
                    {
                        Status: gblOptionSets.JobPhoto.Status.Inactive,
                        'Status Reason': gblOptionSets.JobPhoto.StatusReason.Inactive
                    }
                )
            );
            // remove current job entry from not completed windows collection
            Remove(
                colNotCompletedWindows,
                LookUp(colNotCompletedWindows, 'Window Measurement'=gblRecordWindowMeasurement_Tech.'Window Measurement') 
            );
        )
    );
    // save local changes
    If(
        gblAppLoadOffline,
        SaveData(
            colAUDRecords,
            "localAUDRecords"
        );
        SaveData(
            colCdsWindowMeasurements,
            "localCdsWindowMeasurements"
        );
        SaveData(
            colCdsJobPhotos,
            "localCdsJobPhotos"
        )
    );
    // go to the next screen
    Navigate(
        'Windows Screen',
        BorderStyle.None
    )
);
// create project sidebar
ClearCollect(
    colProjectSidebar,
    Ungroup(
        Filter(
            Table(
                {
                    varMenuItems: RenameColumns(
                        Table(
                            {
                                ID: gblRecordJobEntryCurrent_.'Job Entry',
                                Name: Index(
                                    ForAll(Split(
                                        gblRecordJobEntryCurrent_.'Window Choice'.Name,
                                        " > "
                                    ), {Result: ThisRecord.Value}),
                                    2
                                ).Result,
                                Category: "Job Entry",
                                Description: Index(
                                    ForAll(Split(
                                        gblRecordJobEntryCurrent_.'Window Choice'.Name,
                                        " > "
                                    ), {Result: ThisRecord.Value}),
                                    1
                                ).Result,
                                Screen: 'Windows Screen',
                                Type: "Window Choice",
                                Image: 'dblhungw-2',
                                ImageDisabled: 'dblhungw-2'
                            }
                        ),
                        Name,
                        Title
                    )
                },
                {
                    varMenuItems: ShowColumns(
                        RenameColumns(
                            AddColumns(
                                Filter(
                                    colCdsWindowMeasurements,
                                    'Job Entry'.'Job Entry' = gblRecordJobEntryCurrent_.'Job Entry',
                                    Type = gblOptionSets.WindowMeasurement.Type.Tech,
                                    Status <> gblOptionSets.WindowMeasurement.Status.Inactive
                                ),
                                Category,
                                "Window Measurement",
                                Description,
                                If(
                                    'United Inches (UI)' = 0,
                                    "Sales Measurement",
                                    "Tech Measurement"
                                ),
                                Image,
                                gblAppIcons.Ruler,
                                ImageDisabled,
                                gblAppIcons.RulerDisabled,
                                Screen,
                                'Measure Window Screen',
                                Title,
                                If(
                                    'United Inches (UI)' = 0,
                                    $"{Text(gblRecordJobEntryCurrent_.'Measurement (Sales)'.Width)}"" x {Text(gblRecordJobEntryCurrent_.'Measurement (Sales)'.Height)}""",
                                    $"{RoundDown(
                                        Width,
                                        0
                                    )} {Switch(
                                        Mod(
                                            Width,
                                            1
                                        ),
                                        0,
                                        "",
                                        0.125,
                                        "1/8",
                                        0.250,
                                        "1/4",
                                        0.375,
                                        "3/8",
                                        0.500,
                                        "1/2",
                                        0.625,
                                        "5/8",
                                        0.750,
                                        "3/4",
                                        0.875,
                                        "7/8"
                                    )}"" x {RoundDown(
                                        Height,
                                        0
                                    )} {Switch(
                                        Mod(
                                            Height,
                                            1
                                        ),
                                        0,
                                        "",
                                        0.125,
                                        "1/8",
                                        0.250,
                                        "1/4",
                                        0.375,
                                        "3/8",
                                        0.500,
                                        "1/2",
                                        0.625,
                                        "5/8",
                                        0.750,
                                        "3/4",
                                        0.875,
                                        "7/8"
                                    )}"""
                                )
                            ),
                            'Window Measurement',
                            ID
                        ),
                        ID,
                        Title,
                        Category,
                        Description,
                        Screen,
                        Image,
                        ImageDisabled
                    )
                }
            ),
            !IsEmpty(varMenuItems)
        ),
        varMenuItems
    )
);
If(
    gblProjectSidebarItemCurrent.Category = "Job Entry",
    Set(
        gblProjectSidebarItemCurrent,
        Blank()
    ),
    gblProjectSidebarItemCurrent.Category = "Window Measurement",
    With(
        {
            varGetFirstWindowMeasurement: LookUp(
                colProjectSidebar,
                Category="Window Measurement"
            ),
            varGetJobEntry: LookUp(
                colProjectSidebar,
                Category="Job Entry"
            )
        },
        Set(
            gblProjectSidebarItemCurrent,
            Coalesce(varGetFirstWindowMeasurement, varGetJobEntry)
        )
    )
);
// go to the next screen
If(
    // JOB ENTRY
    gblProjectSidebarItemCurrent.Category = "Job Entry",
    Set(
        gblProjectSidebarItemCurrent,
        Blank()
    );
    Navigate(
        'Rooms Screen',
        BorderStyle.None
    ),
    // WINDOW MEASUREMENT
    gblProjectSidebarItemCurrent.Category = "Window Measurement",
    With(
        {
            varGetFirstWindowMeasurement: LookUp(
                colProjectSidebar,
                Category="Window Measurement"
            ),
            varGetJobEntry: LookUp(
                colProjectSidebar,
                Category="Job Entry"
            )
        },
        If(
            IsBlank(varGetFirstWindowMeasurement),
            // no measurements found in sidebar
            Set(
                gblProjectSidebarItemCurrent,
                varGetJobEntry
            );
            Navigate(
                'Windows Screen',
                BorderStyle.None
            ),
            // measurement found in sidebar
            Set(
                gblProjectSidebarItemCurrent,
                varGetFirstWindowMeasurement
            );
            Navigate(
                'Measure Window Screen',
                BorderStyle.None,
                {locDeletedWindowMeasure: true}
            )
        )
    );
)
